"use client"

import { useEffect, useState } from "react"
import { getIllustrationPosts, hydrateStore } from "@/lib/store"
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel"
import { Card, CardContent } from "@/components/ui/card"
import Image from "next/image"

export default function HomePage() {
  const [images, setImages] = useState<string[]>([])
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    let active = true

    const loadImages = async () => {
      setMounted(true)
      await hydrateStore()

      if (!active) return

      const illustration = getIllustrationPosts()
      const allImages: string[] = []

      illustration.forEach((post) => {
        if (post.images) allImages.push(...post.images)
      })

      // Remove duplicates
      const uniqueImages = Array.from(new Set(allImages))
      setImages(uniqueImages)
    }

    void loadImages()

    return () => {
      active = false
    }
  }, [])

  if (!mounted) return null

  return (
    <div className="space-y-12">
      <section className="text-center py-8">
        <h2 className="text-2xl md:text-3xl font-bold text-foreground mb-4 text-balance">
          고래상어의 세계에 오신 것을 환영합니다
        </h2>
        <p className="text-muted-foreground max-w-2xl mx-auto text-pretty">
          웹툰, 일러스트, 그리고 다양한 작품을 감상하세요.
        </p>
      </section>

      {images.length > 0 ? (
        <section className="py-8 w-full max-w-5xl mx-auto px-12">
          <Carousel
            opts={{
              align: "start",
              loop: true,
            }}
            className="w-full"
          >
            <CarouselContent>
              {images.map((img, index) => (
                <CarouselItem key={index} className="md:basis-1/2 lg:basis-1/3">
                  <div className="p-1">
                    <Card className="overflow-hidden border-none shadow-md hover:shadow-lg transition-shadow">
                      <CardContent className="flex aspect-square items-center justify-center p-0 relative">
                        <Image
                          src={img}
                          alt={`Uploaded work ${index + 1}`}
                          fill
                          className="object-cover"
                        />
                      </CardContent>
                    </Card>
                  </div>
                </CarouselItem>
              ))}
            </CarouselContent>
            <CarouselPrevious />
            <CarouselNext />
          </Carousel>
        </section>
      ) : (
        <section className="text-center py-20 bg-muted/30 rounded-xl border border-border">
          <p className="text-muted-foreground">아직 업로드된 작품이 없습니다.</p>
        </section>
      )}

      <section className="text-center py-8 border-t border-border">
        <p className="text-sm text-muted-foreground">
          작품에 대한 문의나 협업 제안은 작가 프로필을 통해 연락해주세요.
        </p>
      </section>
    </div>
  )
}
